const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');
const http = require('http');

class GrpcClient {
  constructor(protoPath, serviceName, serverAddress) {
    const packageDefinition = protoLoader.loadSync(protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });
    
    const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
    const servicePackage = this.getNestedService(protoDescriptor, serviceName);
    
    this.client = new servicePackage(
      serverAddress,
      grpc.credentials.createInsecure()
    );
  }
  
  getNestedService(obj, path) {
    return path.split('.').reduce((current, key) => current[key], obj);
  }
  
  createMetadataFromHeaders(httpHeaders, customHeaderPrefixes = ['x-', 'authorization', 'user-agent']) {
    const metadata = new grpc.Metadata();
    
    const headersToForward = [
      'user-agent',
      'x-forwarded-for',
      'x-forwarded-proto',
      'x-forwarded-host',
      'x-real-ip',
      'authorization',
      'content-type',
      'accept',
      'accept-language',
      'accept-encoding'
    ];
    
    Object.keys(httpHeaders).forEach(header => {
      const lowerHeader = header.toLowerCase();
      
      const shouldForward = headersToForward.includes(lowerHeader) ||
                           customHeaderPrefixes.some(prefix => lowerHeader.startsWith(prefix));
      
      if (shouldForward) {
        const value = httpHeaders[header];
        if (Array.isArray(value)) {
          value.forEach(v => metadata.add(lowerHeader, v));
        } else {
          metadata.add(lowerHeader, value);
        }
      }
    });
    
    return metadata;
  }
  
  call(method, request, httpHeaders, callback) {
    const metadata = this.createMetadataFromHeaders(httpHeaders);
    
    if (!this.client[method]) {
      return callback(new Error(`Method ${method} not found on gRPC client`));
    }
    
    this.client[method](request, metadata, (error, response) => {
      if (error) {
        return callback(error);
      }
      callback(null, response);
    });
  }
  
  callWithDeadline(method, request, httpHeaders, deadlineMs, callback) {
    const metadata = this.createMetadataFromHeaders(httpHeaders);
    const deadline = new Date(Date.now() + deadlineMs);
    
    if (!this.client[method]) {
      return callback(new Error(`Method ${method} not found on gRPC client`));
    }
    
    this.client[method](request, metadata, { deadline }, (error, response) => {
      if (error) {
        return callback(error);
      }
      callback(null, response);
    });
  }
  
  streamCall(method, httpHeaders) {
    const metadata = this.createMetadataFromHeaders(httpHeaders);
    
    if (!this.client[method]) {
      throw new Error(`Method ${method} not found on gRPC client`);
    }
    
    return this.client[method](metadata);
  }
}

class HttpToGrpcGateway {
  constructor() {
    this.app = express();
    this.grpcClients = new Map();
    
    this.app.use(express.json());
    this.app.use(express.urlencoded({ extended: true }));
  }
  
  registerGrpcService(name, protoPath, serviceName, serverAddress) {
    const client = new GrpcClient(protoPath, serviceName, serverAddress);
    this.grpcClients.set(name, client);
  }
  
  addRoute(httpMethod, httpPath, serviceName, grpcMethod, requestTransformer = null) {
    this.app[httpMethod.toLowerCase()](httpPath, (req, res) => {
      const client = this.grpcClients.get(serviceName);
      
      if (!client) {
        return res.status(500).json({ error: `gRPC service ${serviceName} not found` });
      }
      
      let grpcRequest = requestTransformer 
        ? requestTransformer(req.body, req.params, req.query)
        : req.body;
      
      const headers = { ...req.headers };
      
      if (req.ip) {
        const existingForwardedFor = headers['x-forwarded-for'];
        headers['x-forwarded-for'] = existingForwardedFor 
          ? `${existingForwardedFor}, ${req.ip}`
          : req.ip;
      }
      
      client.call(grpcMethod, grpcRequest, headers, (error, response) => {
        if (error) {
          const statusCode = this.grpcStatusToHttp(error.code);
          return res.status(statusCode).json({
            error: error.message,
            code: error.code,
            details: error.details
          });
        }
        
        res.json(response);
      });
    });
  }
  
  grpcStatusToHttp(grpcCode) {
    const statusMap = {
      0: 200,  // OK
      1: 499,  // CANCELLED
      2: 500,  // UNKNOWN
      3: 400,  // INVALID_ARGUMENT
      4: 504,  // DEADLINE_EXCEEDED
      5: 404,  // NOT_FOUND
      6: 409,  // ALREADY_EXISTS
      7: 403,  // PERMISSION_DENIED
      8: 429,  // RESOURCE_EXHAUSTED
      9: 400,  // FAILED_PRECONDITION
      10: 409, // ABORTED
      11: 400, // OUT_OF_RANGE
      12: 501, // UNIMPLEMENTED
      13: 500, // INTERNAL
      14: 503, // UNAVAILABLE
      15: 500, // DATA_LOSS
      16: 401  // UNAUTHENTICATED
    };
    
    return statusMap[grpcCode] || 500;
  }
  
  start(port) {
    this.server = this.app.listen(port, () => {
      console.log(`HTTP to gRPC Gateway listening on port ${port}`);
    });
  }
  
  stop() {
    if (this.server) {
      this.server.close();
    }
  }
}

const gateway = new HttpToGrpcGateway();

gateway.registerGrpcService(
  'userService',
  './proto/user.proto',
  'user.UserService',
  'localhost:50051'
);

gateway.addRoute('POST', '/api/users', 'userService', 'CreateUser');

gateway.addRoute('GET', '/api/users/:id', 'userService', 'GetUser', (body, params, query) => {
  return { id: params.id };
});

gateway.addRoute('PUT', '/api/users/:id', 'userService', 'UpdateUser', (body, params, query) => {
  return { id: params.id, ...body };
});

gateway.addRoute('DELETE', '/api/users/:id', 'userService', 'DeleteUser', (body, params, query) => {
  return { id: params.id };
});

gateway.start(3000);

module.exports = { GrpcClient, HttpToGrpcGateway };